# phytron.proto
# StreamDevice protocol file for Phytron MCC-1 MINI-W-ETH
# TCP/IP port is configured in st.cmd.
#
# NOTE:
# Command strings are an initial scaffold based on the requested PVs.
# They should be verified against the vendor command manual during bring-up.

Terminator = CR LF;
ReplyTimeout = 1000;
ReadTimeout = 1000;
WriteTimeout = 1000;
LockTimeout = 5000;
ExtraInput = Ignore;

# Read current position readback.
getPos {
    out "POS?";
    in "%f";
}

# Read current speed readback.
getSpeed {
    out "SPEED?";
    in "%f";
}

# Jog or move in positive direction.
movePlus {
    out "MOVE_PLUS";
}

# Jog or move in negative direction.
moveMinus {
    out "MOVE_MINUS";
}

# Stop motion.
stopMove {
    out "STOP";
}
